VALUES ('AL-MED-MAL-STANDARD-OF-CARE', 5, 'AL Medical Malpractice: Standard of Care (Ala. Code § 6-5-484)', 'content_check', 'personal_injury', 'medical_malpractice', 'complaint', 'state', 'AL',
    jsonb_build_object('sub_specialization_type', 'medical_malpractice', 'authority_level', 'contextual_rule', 'statute', 'Ala. Code § 6-5-484', 'standard_text', 'The standard of care is that degree of care, skill, and diligence used by similarly situated health care providers in the same general neighborhood', 'key_elements', jsonb_build_array('Duty: provider-patient relationship established', 'Breach: failure to meet standard of care in same community', 'Causation: breach proximately caused plaintiff injury', 'Damages: actual injury/harm resulted'), 'locality_rule', 'Alabama applies a same-general-neighborhood/community standard — a modified locality rule', 'res_ipsa', 'Doctrine of res ipsa loquitur available in limited circumstances (e.g., foreign object left in body)', 'informed_consent', 'Separate theory of recovery; provider must disclose material risks a reasonable patient would want to know', 'verification', jsonb_build_object('statute_verified', true, 'sources', jsonb_build_array('Ala. Code § 6-5-484', 'Alabama Medical Liability Act of 1987', 'Justia — Alabama Medical Liability'), 'confidence', 'high')),
